-- SIPEN — Importação Agenda IPPenha 2026 (905 eventos)
-- Executar no SQL Editor do Supabase
-- ══════════════════════════════════════════════════════════════════════

-- PASSO 1: Preparar tabela agenda (adicionar colunas que faltam)
ALTER TABLE public.agenda ALTER COLUMN data_inicio DROP NOT NULL;

ALTER TABLE public.agenda
  ADD COLUMN IF NOT EXISTS data        date,
  ADD COLUMN IF NOT EXISTS mes         text,
  ADD COLUMN IF NOT EXISTS semana      text,
  ADD COLUMN IF NOT EXISTS dia_semana  text,
  ADD COLUMN IF NOT EXISTS hora_inicio text,
  ADD COLUMN IF NOT EXISTS hora_fim    text,
  ADD COLUMN IF NOT EXISTS organizador text,
  ADD COLUMN IF NOT EXISTS responsavel text,
  ADD COLUMN IF NOT EXISTS espaco      text,
  ADD COLUMN IF NOT EXISTS observacao  text;

CREATE INDEX IF NOT EXISTS idx_agenda_data   ON public.agenda(data)   WHERE data IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_agenda_mes    ON public.agenda(mes)    WHERE mes  IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_agenda_espaco ON public.agenda(espaco) WHERE espaco IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS idx_agenda_uniq
  ON public.agenda(titulo, data, COALESCE(hora_inicio,''))
  WHERE deleted_at IS NULL;

-- Recriar constraint de status para garantir valores corretos
ALTER TABLE public.agenda DROP CONSTRAINT IF EXISTS agenda_status_check;
ALTER TABLE public.agenda ADD CONSTRAINT agenda_status_check
  CHECK (status IN ('pendente','confirmado','cancelado','realizado','reagendado'));

-- PASSO 2: Inserir 905 eventos (ignora duplicatas automaticamente)
ON CONFLICT DO NOTHING;

-- PASSO 3: Verificar resultado
SELECT mes, COUNT(*) AS total FROM public.agenda GROUP BY mes ORDER BY MIN(data);
